# --- Authentication & Authorization ---

def get_authenticated_user(context):
    """Extract authenticated user from context. Returns None if not authenticated."""
    user = getattr(context, 'user', None)
    if user is None:
        return None
    if not getattr(user, 'id', None):
        return None
    return user


def require_authentication(func):
    """Decorator to require authentication."""
    @wraps(func)
    def wrapper(root, info, *args, **kwargs):
        user = get_authenticated_user(info.context)
        if user is None:
            raise AuthorizationError("Authentication required.")
        return func(root, info, *args, **kwargs)
    return wrapper


def check_field_authorization(authenticated_user, target_user_id, fields_being_updated):
    """
    Check if the authenticated user is authorized to update the specified fields
    on the target user's profile.

    - Users can update their own SELF_EDITABLE_FIELDS.
    - Only admins can update ADMIN_ONLY_FIELDS.
    - Only admins can update other users' profiles.
    """
    is_self_update = authenticated_user.id == target_user_id
    is_admin = getattr(authenticated_user, 'is_admin', False)

    if not is_self_update and not is_admin:
        raise AuthorizationError("You can only update your own profile.")

    admin_fields_requested = fields_being_updated & ADMIN_ONLY_FIELDS
    if admin_fields_requested and not is_admin:
        raise AuthorizationError(
            f"Insufficient permissions. The following fields require admin privileges: "
            f"{', '.join(sorted(admin_fields_requested))}"
        )

    if is_self_update and not is_admin:
        disallowed = fields_being_updated - SELF_EDITABLE_FIELDS
        if disallowed:
            raise AuthorizationError(
                f"You are not allowed to modify: {', '.join(sorted(disallowed))}"
            )


# --- Input Validation ---

def validate_username(username):
    """Validate username format and length."""
    if len(username) < MIN_USERNAME_LENGTH:
        raise ValidationError(f"Username must be at least {MIN_USERNAME_LENGTH} characters.")
    if len(username) > MAX_USERNAME_LENGTH:
        raise ValidationError(f"Username must be at most {MAX_USERNAME_LENGTH} characters.")
    if not USERNAME_PATTERN.match(username):
        raise ValidationError("Username can only contain letters, numbers, and underscores.")
    # Check uniqueness
    for uid, user in USERS_DB.items():
        if user.username.lower() == username.lower():
            # Allow if it's the same user keeping their username
            return uid
    return None


def validate_email(email):
    """Validate email format."""
    if len(email) > 254:
        raise ValidationError("Email address is too long.")
    if not EMAIL_PATTERN.match(email):
        raise ValidationError("Invalid email format.")
    # Check uniqueness
    for uid, user in USERS_DB.items():
        if user.email.lower() == email.lower():
            return uid
    return None


def validate_bio(bio):
    """Validate and sanitize bio."""
    if len(bio) > MAX_BIO_LENGTH:
        raise ValidationError(f"Bio must be at most {MAX_BIO_LENGTH} characters.")
    # Sanitize HTML to prevent stored XSS
    return html.escape(bio)


def validate_role(role):
    """Validate role value."""
    if role not in VALID_ROLES:
        raise ValidationError(f"Invalid role. Must be one of: {', '.join(sorted(VALID_ROLES))}")


def validate_credits(credits):
    """Validate credits value."""
    if credits < 0:
        raise ValidationError("Credits cannot be negative.")
    if credits > 1_000_000:
        raise ValidationError("Credits value exceeds maximum allowed.")


def validate_subscription_tier(tier):
    """Validate subscription tier."""
    if tier not in VALID_SUBSCRIPTION_TIERS:
        raise ValidationError(
            f"Invalid subscription tier. Must be one of: {', '.join(sorted(VALID_SUBSCRIPTION_TIERS))}"
        )


