# --- Schema with query depth/complexity limiting middleware ---

class QueryDepthMiddleware:
    """
    Middleware to limit query depth and prevent deeply nested malicious queries.
    """
    MAX_DEPTH = 10

    def resolve(self, next, root, info, **args):
        # Check depth based on field path
        path = info.path
        depth = 0
        current = path
        while current is not None:
            depth += 1
            current = getattr(current, 'prev', None)

        if depth > self.MAX_DEPTH:
            raise Exception(f"Query depth {depth} exceeds maximum allowed depth of {self.MAX_DEPTH}.")

        return next(root, info, **args)


